#include <stdio.h>
#include <limits.h>

long long calculateMaxProfit(int K, int *price, int N) {
    if (N == 0 || K == 0) return 0;
    if (K >= N/2) {
        long long profit = 0;
        for (int i = 1; i < N; ++i) if (price[i] > price[i-1]) profit += price[i] - price[i-1];
        return profit;
    }
    long long buy[K+1];
    long long sell[K+1];
    for (int t = 0; t <= K; ++t) {
        buy[t] = LLONG_MIN;
        sell[t] = 0;
    }
    for (int i = 0; i < N; ++i) {
        for (int t = 1; t <= K; ++t) {
            if (sell[t-1] - price[i] > buy[t]) buy[t] = sell[t-1] - price[i];
            if (buy[t] + price[i] > sell[t]) sell[t] = buy[t] + price[i];
        }
    }
    return sell[K];
}

int main() {
    int T; scanf("%d", &T);
    while (T--) {
        int K, N; scanf("%d %d", &K, &N);
        int price[N];
        for (int i = 0; i < N; ++i) scanf("%d", &price[i]);
        printf("%lld\n", calculateMaxProfit(K, price, N));
    }
    return 0;
}

