#include <bits/stdc++.h>
using namespace std;

long long calculateMaxProfit(int K, const vector<int>& price) {
    int N = price.size();
    if (N == 0 || K == 0) return 0;
    if (K >= N/2) {
        long long profit = 0;
        for (int i = 1; i < N; ++i) if (price[i] > price[i-1]) profit += price[i] - price[i-1];
        return profit;
    }
    vector<long long> buy(K+1, LLONG_MIN), sell(K+1, 0);
    for (int p : price) {
        for (int t = 1; t <= K; ++t) {
            buy[t] = max(buy[t], sell[t-1] - p);
            sell[t] = max(sell[t], buy[t] + p);
        }
    }
    return sell[K];
}

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int T; cin >> T;
    while (T--) {
        int K, N; cin >> K >> N;
        vector<int> price(N);
        for (int i = 0; i < N; ++i) cin >> price[i];
        cout << calculateMaxProfit(K, price) << '\n';
    }
    return 0;
}

