import java.io.*;
import java.util.*;

public class Main {
    private static long calculateMaxProfit(int K, int[] price) {
        int N = price.length;
        if (N == 0 || K == 0) return 0;
        if (K >= N/2) {
            long profit = 0;
            for (int i = 1; i < N; ++i) if (price[i] > price[i-1]) profit += price[i] - price[i-1];
            return profit;
        }
        long[] buy = new long[K+1];
        long[] sell = new long[K+1];
        Arrays.fill(buy, Long.MIN_VALUE);
        Arrays.fill(sell, 0L);
        for (int p : price) {
            for (int t = 1; t <= K; ++t) {
                buy[t] = Math.max(buy[t], sell[t-1] - p);
                sell[t] = Math.max(sell[t], buy[t] + p);
            }
        }
        return sell[K];
    }

    public static void main(String[] args) throws Exception {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        StringTokenizer st;
        int T = Integer.parseInt(br.readLine().trim());
        StringBuilder sb = new StringBuilder();
        while (T-- > 0) {
            st = new StringTokenizer(br.readLine());
            int K = Integer.parseInt(st.nextToken());
            int N = Integer.parseInt(st.nextToken());
            int[] price = new int[N];
            st = new StringTokenizer(br.readLine());
            for (int i = 0; i < N; ++i) price[i] = Integer.parseInt(st.nextToken());
            sb.append(calculateMaxProfit(K, price)).append('\n');
        }
        System.out.print(sb.toString());
    }
}

