import sys

def calculate_max_profit(K, prices):
    N = len(prices)
    if N == 0 or K == 0:
        return 0
    if K >= N // 2:
        profit = 0
        for i in range(1, N):
            if prices[i] > prices[i-1]:
                profit += prices[i] - prices[i-1]
        return profit
    buy = [-10**18] * (K + 1)
    sell = [0] * (K + 1)
    for p in prices:
        for t in range(1, K + 1):
            buy[t] = max(buy[t], sell[t-1] - p)
            sell[t] = max(sell[t], buy[t] + p)
    return sell[K]

def main():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out_lines = []
    for _ in range(T):
        K = int(next(it))
        N = int(next(it))
        prices = [int(next(it)) for _ in range(N)]
        out_lines.append(str(calculate_max_profit(K, prices)))
    sys.stdout.write('\n'.join(out_lines))

if __name__ == "__main__":
    main()

