    if (K >= Math.floor(N / 2)) {
        let profit = 0;
        for (let i = 1; i < N; ++i) if (prices[i] > prices[i-1]) profit += prices[i] - prices[i-1];
        outputs.push(String(profit));
        continue;
    }
    const buy = new Array(K + 1).fill(Number.NEGATIVE_INFINITY);
    const sell = new Array(K + 1).fill(0);
    for (const p of prices) {
        for (let t = 1; t <= K; ++t) {
            if (sell[t-1] - p > buy[t]) buy[t] = sell[t-1] - p;
            if (buy[t] + p > sell[t]) sell[t] = buy[t] + p;
        }
    }
    outputs.push(String(sell[K]));
